import json
with open(var_call_hSSmcl5suLX2SXtUEpdsSLFO, 'r') as f:
    records = json.load(f)
lines = []
for r in records:
    book_id = r.get('book_id','')
    title = r.get('title','')
    author = r.get('author')
    # parse author JSON if possible
    if isinstance(author, str):
        a = author.strip()
        if a in ('None','null',''):
            author_name = None
        else:
            try:
                parsed = json.loads(a)
                if isinstance(parsed, dict):
                    author_name = parsed.get('name')
                else:
                    author_name = str(parsed)
            except Exception:
                author_name = a
    else:
        author_name = author
    avg = r.get('avg_rating')
    cnt = r.get('review_count')
    lines.append(f"{title} (book_id: {book_id}) — Author: {author_name if author_name else 'Unknown'} — Avg rating: {avg} — Review count: {cnt}")
answer_text = '\n'.join(lines)
print('__RESULT__:')
print(json.dumps(answer_text))

